CREATE DATABASE IF NOT EXISTS edtts; USE edtts;
CREATE TABLE contacts(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(100),email VARCHAR(120),phone VARCHAR(30),subject VARCHAR(200),message TEXT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE quotes(id INT AUTO_INCREMENT PRIMARY KEY,customer_name VARCHAR(100),company_name VARCHAR(120),email VARCHAR(120),phone VARCHAR(30),service VARCHAR(100),description TEXT,budget VARCHAR(50),delivery_date DATE,file_name VARCHAR(255),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);